    python: "class Solution:\n    def maxArea(self, height: List[int]) -> int:\n        l, r = 0, len(height) - 1\n        ans = 0\n        while l < r:\n            t = min(height[l], height[r]) * (r - l)\n            ans = max(ans, t)\n            if height[l] < height[r]:\n                l += 1\n            else:\n                r -= 1\n        return ans\n",
    java: "class Solution {\n    public int maxArea(int[] height) {\n        int l = 0, r = height.length - 1;\n        int ans = 0;\n        while (l < r) {\n            int t = Math.min(height[l], height[r]) * (r - l);\n            ans = Math.max(ans, t);\n            if (height[l] < height[r]) {\n                ++l;\n            } else {\n                --r;\n            }\n        }\n        return ans;\n    }\n}\n",
