    python: "class Solution:\n    def threeSumClosest(self, nums: List[int], target: int) -> int:\n        nums.sort()\n        n = len(nums)\n        ans = inf\n        for i, v in enumerate(nums):\n            j, k = i + 1, n - 1\n            while j < k:\n                t = v + nums[j] + nums[k]\n                if t == target:\n                    return t\n                if abs(t - target) < abs(ans - target):\n                    ans = t\n                if t > target:\n                    k -= 1\n                else:\n                    j += 1\n        return ans\n",
    java: "class Solution {\n    public int threeSumClosest(int[] nums, int target) {\n        Arrays.sort(nums);\n        int ans = 1 << 30;\n        int n = nums.length;\n        for (int i = 0; i < n; ++i) {\n            int j = i + 1, k = n - 1;\n            while (j < k) {\n                int t = nums[i] + nums[j] + nums[k];\n                if (t == target) {\n                    return t;\n                }\n                if (Math.abs(t - target) < Math.abs(ans - target)) {\n                    ans = t;\n                }\n                if (t > target) {\n                    --k;\n                } else {\n                    ++j;\n                }\n            }\n        }\n        return ans;\n    }\n}",
