    java: "class Solution {\n    public String simplifyPath(String path) {\n        Deque<String> stk = new ArrayDeque<>();\n        for (String s : path.split(\"/\")) {\n            if (\"\".equals(s) || \".\".equals(s)) {\n                continue;\n            }\n            if (\"..\".equals(s)) {\n                stk.pollLast();\n            } else {\n                stk.offerLast(s);\n            }\n        }\n        return \"/\" + String.join(\"/\", stk);\n    }\n}",
