    python: "class Solution:\n    def combine(self, n: int, k: int) -> List[List[int]]:\n        def dfs(i: int):\n            if len(t) == k:\n                ans.append(t[:])\n                return\n            if i > n:\n                return\n            t.append(i)\n            dfs(i + 1)\n            t.pop()\n            dfs(i + 1)\n\n        ans = []\n        t = []\n        dfs(1)\n        return ans\n",
    java: "class Solution {\n    private List<List<Integer>> ans = new ArrayList<>();\n    private List<Integer> t = new ArrayList<>();\n    private int n;\n    private int k;\n\n    public List<List<Integer>> combine(int n, int k) {\n        this.n = n;\n        this.k = k;\n        dfs(1);\n        return ans;\n    }\n\n    private void dfs(int i) {\n        if (t.size() == k) {\n            ans.add(new ArrayList<>(t));\n            return;\n        }\n        if (i > n) {\n            return;\n        }\n        t.add(i);\n        dfs(i + 1);\n        t.remove(t.size() - 1);\n        dfs(i + 1);\n    }\n}",
