    python: "class Solution:\n    def ladderLength(self, beginWord: str, endWord: str, wordList: List[str]) -> int:\n        words = set(wordList)\n        q = deque([beginWord])\n        ans = 1\n        while q:\n            ans += 1\n            for _ in range(len(q)):\n                s = q.popleft()\n                s = list(s)\n                for i in range(len(s)):\n                    ch = s[i]\n                    for j in range(26):\n                        s[i] = chr(ord('a') + j)\n                        t = ''.join(s)\n                        if t not in words:\n                            continue\n                        if t == endWord:\n                            return ans\n                        q.append(t)\n                        words.remove(t)\n                    s[i] = ch\n        return 0\n",
    java: "class Solution {\n    public int ladderLength(String beginWord, String endWord, List<String> wordList) {\n        Set<String> words = new HashSet<>(wordList);\n        Queue<String> q = new ArrayDeque<>();\n        q.offer(beginWord);\n        int ans = 1;\n        while (!q.isEmpty()) {\n            ++ans;\n            for (int i = q.size(); i > 0; --i) {\n                String s = q.poll();\n                char[] chars = s.toCharArray();\n                for (int j = 0; j < chars.length; ++j) {\n                    char ch = chars[j];\n                    for (char k = 'a'; k <= 'z'; ++k) {\n                        chars[j] = k;\n                        String t = new String(chars);\n                        if (!words.contains(t)) {\n                            continue;\n                        }\n                        if (endWord.equals(t)) {\n                            return ans;\n                        }\n                        q.offer(t);\n                        words.remove(t);\n                    }\n                    chars[j] = ch;\n                }\n            }\n        }\n        return 0;\n    }\n}",
