    python: "class Solution:\n    def longestConsecutive(self, nums: List[int]) -> int:\n        s = set(nums)\n        ans = 0\n        d = defaultdict(int)\n        for x in nums:\n            y = x\n            while y in s:\n                s.remove(y)\n                y += 1\n            d[x] = d[y] + y - x\n            ans = max(ans, d[x])\n        return ans\n",
    java: "class Solution {\n    public int longestConsecutive(int[] nums) {\n        Set<Integer> s = new HashSet<>();\n        for (int x : nums) {\n            s.add(x);\n        }\n        int ans = 0;\n        Map<Integer, Integer> d = new HashMap<>();\n        for (int x : nums) {\n            int y = x;\n            while (s.contains(y)) {\n                s.remove(y++);\n            }\n            d.put(x, d.getOrDefault(y, 0) + y - x);\n            ans = Math.max(ans, d.get(x));\n        }\n        return ans;\n    }\n}\n",
