    python: "class Solution:\n    def canCompleteCircuit(self, gas: List[int], cost: List[int]) -> int:\n        n = len(gas)\n        i = j = n - 1\n        cnt = s = 0\n        while cnt < n:\n            s += gas[j] - cost[j]\n            cnt += 1\n            j = (j + 1) % n\n            while s < 0 and cnt < n:\n                i -= 1\n                s += gas[i] - cost[i]\n                cnt += 1\n        return -1 if s < 0 else i\n",
    java: "class Solution {\n    public int canCompleteCircuit(int[] gas, int[] cost) {\n        int n = gas.length;\n        int i = n - 1, j = n - 1;\n        int cnt = 0, s = 0;\n        while (cnt < n) {\n            s += gas[j] - cost[j];\n            ++cnt;\n            j = (j + 1) % n;\n            while (s < 0 && cnt < n) {\n                --i;\n                s += gas[i] - cost[i];\n                ++cnt;\n            }\n        }\n        return s < 0 ? -1 : i;\n    }\n}",
