    python: "\"\"\"\n# Definition for a Node.\nclass Node:\n    def __init__(self, x: int, next: 'Node' = None, random: 'Node' = None):\n        self.val = int(x)\n        self.next = next\n        self.random = random\n\"\"\"\n\n\nclass Solution:\n    def copyRandomList(self, head: \"Optional[Node]\") -> \"Optional[Node]\":\n        d = {}\n        dummy = tail = Node(0)\n        cur = head\n        while cur:\n            node = Node(cur.val)\n            tail.next = node\n            tail = tail.next\n            d[cur] = node\n            cur = cur.next\n        cur = head\n        while cur:\n            d[cur].random = d[cur.random] if cur.random else None\n            cur = cur.next\n        return dummy.next\n",
    java: "/*\n// Definition for a Node.\nclass Node {\n    int val;\n    Node next;\n    Node random;\n\n    public Node(int val) {\n        this.val = val;\n        this.next = null;\n        this.random = null;\n    }\n}\n*/\n\nclass Solution {\n    public Node copyRandomList(Node head) {\n        Map<Node, Node> d = new HashMap<>();\n        Node dummy = new Node(0);\n        Node tail = dummy;\n        for (Node cur = head; cur != null; cur = cur.next) {\n            Node node = new Node(cur.val);\n            tail.next = node;\n            tail = node;\n            d.put(cur, node);\n        }\n        for (Node cur = head; cur != null; cur = cur.next) {\n            d.get(cur).random = cur.random == null ? null : d.get(cur.random);\n        }\n        return dummy.next;\n    }\n}\n",
