    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def maxPoints(self, points: List[List[int]]) -> int:\n        n = len(points)\n        ans = 1\n        for i in range(n):\n            x1, y1 = points[i]\n            for j in range(i + 1, n):\n                x2, y2 = points[j]\n                cnt = 2\n                for k in range(j + 1, n):\n                    x3, y3 = points[k]\n                    a = (y2 - y1) * (x3 - x1)\n                    b = (y3 - y1) * (x2 - x1)\n                    cnt += a == b\n                ans = max(ans, cnt)\n        return ans\n",
    java: "class Solution {\n    public int maxPoints(int[][] points) {\n        int n = points.length;\n        int ans = 1;\n        for (int i = 0; i < n; ++i) {\n            int x1 = points[i][0], y1 = points[i][1];\n            for (int j = i + 1; j < n; ++j) {\n                int x2 = points[j][0], y2 = points[j][1];\n                int cnt = 2;\n                for (int k = j + 1; k < n; ++k) {\n                    int x3 = points[k][0], y3 = points[k][1];\n                    int a = (y2 - y1) * (x3 - x1);\n                    int b = (y3 - y1) * (x2 - x1);\n                    if (a == b) {\n                        ++cnt;\n                    }\n                }\n                ans = Math.max(ans, cnt);\n            }\n        }\n        return ans;\n    }\n}",
