    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "import operator\n\n\nclass Solution:\n    def evalRPN(self, tokens: List[str]) -> int:\n        opt = {\n            \"+\": operator.add,\n            \"-\": operator.sub,\n            \"*\": operator.mul,\n            \"/\": operator.truediv,\n        }\n        s = []\n        for token in tokens:\n            if token in opt:\n                s.append(int(opt[token](s.pop(-2), s.pop(-1))))\n            else:\n                s.append(int(token))\n        return s[0]\n",
    java: "class Solution {\n    public int evalRPN(String[] tokens) {\n        Deque<Integer> stk = new ArrayDeque<>();\n        for (String t : tokens) {\n            if (t.length() > 1 || Character.isDigit(t.charAt(0))) {\n                stk.push(Integer.parseInt(t));\n            } else {\n                int y = stk.pop();\n                int x = stk.pop();\n                switch (t) {\n                case \"+\":\n                    stk.push(x + y);\n                    break;\n                case \"-\":\n                    stk.push(x - y);\n                    break;\n                case \"*\":\n                    stk.push(x * y);\n                    break;\n                default:\n                    stk.push(x / y);\n                    break;\n                }\n            }\n        }\n        return stk.pop();\n    }\n}",
