    java: "class Solution {\n    public int[] twoSum(int[] numbers, int target) {\n        for (int i = 0, n = numbers.length;; ++i) {\n            int x = target - numbers[i];\n            int l = i + 1, r = n - 1;\n            while (l < r) {\n                int mid = (l + r) >> 1;\n                if (numbers[mid] >= x) {\n                    r = mid;\n                } else {\n                    l = mid + 1;\n                }\n            }\n            if (numbers[l] == x) {\n                return new int[] {i + 1, l + 1};\n            }\n        }\n    }\n}",
