    python: "class Solution:\n    def rotate(self, nums: List[int], k: int) -> None:\n        def reverse(i: int, j: int):\n            while i < j:\n                nums[i], nums[j] = nums[j], nums[i]\n                i, j = i + 1, j - 1\n\n        n = len(nums)\n        k %= n\n        reverse(0, n - 1)\n        reverse(0, k - 1)\n        reverse(k, n - 1)\n",
    java: "class Solution {\n    private int[] nums;\n\n    public void rotate(int[] nums, int k) {\n        this.nums = nums;\n        int n = nums.length;\n        k %= n;\n        reverse(0, n - 1);\n        reverse(0, k - 1);\n        reverse(k, n - 1);\n    }\n\n    private void reverse(int i, int j) {\n        for (; i < j; ++i, --j) {\n            int t = nums[i];\n            nums[i] = nums[j];\n            nums[j] = t;\n        }\n    }\n}",
