    python: "class Solution:\n    def rob(self, nums: List[int]) -> int:\n        @cache\n        def dfs(i: int) -> int:\n            if i >= len(nums):\n                return 0\n            return max(nums[i] + dfs(i + 2), dfs(i + 1))\n\n        return dfs(0)\n",
    java: "class Solution {\n    private Integer[] f;\n    private int[] nums;\n\n    public int rob(int[] nums) {\n        this.nums = nums;\n        f = new Integer[nums.length];\n        return dfs(0);\n    }\n\n    private int dfs(int i) {\n        if (i >= nums.length) {\n            return 0;\n        }\n        if (f[i] == null) {\n            f[i] = Math.max(nums[i] + dfs(i + 2), dfs(i + 1));\n        }\n        return f[i];\n    }\n}\n",
