    python: "class Solution:\n    def isHappy(self, n: int) -> bool:\n        vis = set()\n        while n != 1 and n not in vis:\n            vis.add(n)\n            x = 0\n            while n:\n                n, v = divmod(n, 10)\n                x += v * v\n            n = x\n        return n == 1\n",
    java: "class Solution {\n    public boolean isHappy(int n) {\n        Set<Integer> vis = new HashSet<>();\n        while (n != 1 && !vis.contains(n)) {\n            vis.add(n);\n            int x = 0;\n            while (n != 0) {\n                x += (n % 10) * (n % 10);\n                n /= 10;\n            }\n            n = x;\n        }\n        return n == 1;\n    }\n}",
