    python: "# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, val=0, next=None):\n#         self.val = val\n#         self.next = next\nclass Solution:\n    def reverseList(self, head: ListNode) -> ListNode:\n        dummy = ListNode()\n        curr = head\n        while curr:\n            next = curr.next\n            curr.next = dummy.next\n            dummy.next = curr\n            curr = next\n        return dummy.next\n",
