    python: "class Solution:\n    def minMeetingRooms(self, intervals: List[List[int]]) -> int:\n        m = max(e[1] for e in intervals)\n        d = [0] * (m + 1)\n        for l, r in intervals:\n            d[l] += 1\n            d[r] -= 1\n        ans = s = 0\n        for v in d:\n            s += v\n            ans = max(ans, s)\n        return ans\n",
    java: "class Solution {\n    public int minMeetingRooms(int[][] intervals) {\n        int m = 0;\n        for (var e : intervals) {\n            m = Math.max(m, e[1]);\n        }\n        int[] d = new int[m + 1];\n        for (var e : intervals) {\n            ++d[e[0]];\n            --d[e[1]];\n        }\n        int ans = 0, s = 0;\n        for (int v : d) {\n            s += v;\n            ans = Math.max(ans, s);\n        }\n        return ans;\n    }\n}\n",
