    python: "class Solution:\n    def validTree(self, n: int, edges: List[List[int]]) -> bool:\n        def find(x: int) -> int:\n            if p[x] != x:\n                p[x] = find(p[x])\n            return p[x]\n\n        p = list(range(n))\n        for a, b in edges:\n            pa, pb = find(a), find(b)\n            if pa == pb:\n                return False\n            p[pa] = pb\n            n -= 1\n        return n == 1\n",
    java: "class Solution {\n    private int[] p;\n\n    public boolean validTree(int n, int[][] edges) {\n        p = new int[n];\n        for (int i = 0; i < n; ++i) {\n            p[i] = i;\n        }\n        for (var e : edges) {\n            int pa = find(e[0]), pb = find(e[1]);\n            if (pa == pb) {\n                return false;\n            }\n            p[pa] = pb;\n            --n;\n        }\n        return n == 1;\n    }\n\n    private int find(int x) {\n        if (p[x] != x) {\n            p[x] = find(p[x]);\n        }\n        return p[x];\n    }\n}",
