    python: "class Solution:\n    def hIndex(self, citations: List[int]) -> int:\n        n = len(citations)\n        left, right = 0, n\n        while left < right:\n            mid = (left + right + 1) >> 1\n            if citations[n - mid] >= mid:\n                left = mid\n            else:\n                right = mid - 1\n        return left\n",
    java: "class Solution {\n    public int hIndex(int[] citations) {\n        int n = citations.length;\n        int left = 0, right = n;\n        while (left < right) {\n            int mid = (left + right) >>> 1;\n            if (citations[mid] >= n - mid) {\n                right = mid;\n            } else {\n                left = mid + 1;\n            }\n        }\n        return n - left;\n    }\n}",
