    python: "class Solution:\n    def findDuplicate(self, nums: List[int]) -> int:\n        def f(x: int) -> bool:\n            return sum(v <= x for v in nums) > x\n\n        return bisect_left(range(len(nums)), True, key=f)\n",
    java: "class Solution {\n    public int findDuplicate(int[] nums) {\n        int l = 0, r = nums.length - 1;\n        while (l < r) {\n            int mid = (l + r) >> 1;\n            int cnt = 0;\n            for (int v : nums) {\n                if (v <= mid) {\n                    ++cnt;\n                }\n            }\n            if (cnt > mid) {\n                r = mid;\n            } else {\n                l = mid + 1;\n            }\n        }\n        return l;\n    }\n}",
