    python: "class Solution:\n    def wiggleSort(self, nums: List[int]) -> None:\n        \"\"\"\n        Do not return anything, modify nums in-place instead.\n        \"\"\"\n        arr = sorted(nums)\n        n = len(arr)\n        i, j = (n - 1) >> 1, n - 1\n        for k in range(n):\n            if k % 2 == 0:\n                nums[k] = arr[i]\n                i -= 1\n            else:\n                nums[k] = arr[j]\n                j -= 1\n",
    java: "class Solution {\n    public void wiggleSort(int[] nums) {\n        int[] arr = nums.clone();\n        Arrays.sort(arr);\n        int n = nums.length;\n        int i = (n - 1) >> 1, j = n - 1;\n        for (int k = 0; k < n; ++k) {\n            if (k % 2 == 0) {\n                nums[k] = arr[i--];\n            } else {\n                nums[k] = arr[j--];\n            }\n        }\n    }\n}",
