    python: "class Solution:\n    def integerBreak(self, n: int) -> int:\n        f = [1] * (n + 1)\n        for i in range(2, n + 1):\n            for j in range(1, i):\n                f[i] = max(f[i], f[i - j] * j, (i - j) * j)\n        return f[n]\n",
    java: "class Solution {\n    public int integerBreak(int n) {\n        int[] f = new int[n + 1];\n        f[1] = 1;\n        for (int i = 2; i <= n; ++i) {\n            for (int j = 1; j < i; ++j) {\n                f[i] = Math.max(Math.max(f[i], f[i - j] * j), (i - j) * j);\n            }\n        }\n        return f[n];\n    }\n}",
