    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def sortTransformedArray(\n        self, nums: List[int], a: int, b: int, c: int\n    ) -> List[int]:\n        def f(x: int) -> int:\n            return a * x * x + b * x + c\n\n        n = len(nums)\n        i, j = 0, n - 1\n        ans = [0] * n\n        for k in range(n):\n            y1, y2 = f(nums[i]), f(nums[j])\n            if a > 0:\n                if y1 > y2:\n                    ans[n - k - 1] = y1\n                    i += 1\n                else:\n                    ans[n - k - 1] = y2\n                    j -= 1\n            else:\n                if y1 > y2:\n                    ans[k] = y2\n                    j -= 1\n                else:\n                    ans[k] = y1\n                    i += 1\n        return ans\n",
    java: "class Solution {\n    public int[] sortTransformedArray(int[] nums, int a, int b, int c) {\n        int n = nums.length;\n        int[] ans = new int[n];\n        int i = 0, j = n - 1;\n\n        IntUnaryOperator f = x -> a * x * x + b * x + c;\n\n        for (int k = 0; k < n; k++) {\n            int y1 = f.applyAsInt(nums[i]);\n            int y2 = f.applyAsInt(nums[j]);\n            if (a > 0) {\n                if (y1 > y2) {\n                    ans[n - k - 1] = y1;\n                    i++;\n                } else {\n                    ans[n - k - 1] = y2;\n                    j--;\n                }\n            } else {\n                if (y1 > y2) {\n                    ans[k] = y2;\n                    j--;\n                } else {\n                    ans[k] = y1;\n                    i++;\n                }\n            }\n        }\n        return ans;\n    }\n}\n",
