    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def maxSumSubmatrix(self, matrix: List[List[int]], k: int) -> int:\n        m, n = len(matrix), len(matrix[0])\n        ans = -inf\n        for i in range(m):\n            nums = [0] * n\n            for j in range(i, m):\n                for h in range(n):\n                    nums[h] += matrix[j][h]\n                s = 0\n                ts = SortedSet([0])\n                for x in nums:\n                    s += x\n                    p = ts.bisect_left(s - k)\n                    if p != len(ts):\n                        ans = max(ans, s - ts[p])\n                    ts.add(s)\n        return ans\n",
    java: "class Solution {\n    public int maxSumSubmatrix(int[][] matrix, int k) {\n        int m = matrix.length;\n        int n = matrix[0].length;\n        final int inf = 1 << 30;\n        int ans = -inf;\n        for (int i = 0; i < m; ++i) {\n            int[] nums = new int[n];\n            for (int j = i; j < m; ++j) {\n                for (int h = 0; h < n; ++h) {\n                    nums[h] += matrix[j][h];\n                }\n                int s = 0;\n                TreeSet<Integer> ts = new TreeSet<>();\n                ts.add(0);\n                for (int x : nums) {\n                    s += x;\n                    Integer y = ts.ceiling(s - k);\n                    if (y != null) {\n                        ans = Math.max(ans, s - y);\n                    }\n                    ts.add(s);\n                }\n            }\n        }\n        return ans;\n    }\n}",
