    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\r\n    def wiggleMaxLength(self, nums: List[int]) -> int:\r\n        n = len(nums)\r\n        ans = 1\r\n        f = [1] * n\r\n        g = [1] * n\r\n        for i in range(1, n):\r\n            for j in range(i):\r\n                if nums[j] < nums[i]:\r\n                    f[i] = max(f[i], g[j] + 1)\r\n                elif nums[j] > nums[i]:\r\n                    g[i] = max(g[i], f[j] + 1)\r\n            ans = max(ans, f[i], g[i])\r\n        return ans\r\n",
    java: "class Solution {\r\n    public int wiggleMaxLength(int[] nums) {\r\n        int n = nums.length;\r\n        int ans = 1;\r\n        int[] f = new int[n];\r\n        int[] g = new int[n];\r\n        f[0] = 1;\r\n        g[0] = 1;\r\n        for (int i = 1; i < n; ++i) {\r\n            for (int j = 0; j < i; ++j) {\r\n                if (nums[j] < nums[i]) {\r\n                    f[i] = Math.max(f[i], g[j] + 1);\r\n                } else if (nums[j] > nums[i]) {\r\n                    g[i] = Math.max(g[i], f[j] + 1);\r\n                }\r\n            }\r\n            ans = Math.max(ans, Math.max(f[i], g[i]));\r\n        }\r\n        return ans;\r\n    }\r\n}",
