    python: "class Solution:\n    def findNthDigit(self, n: int) -> int:\n        k, cnt = 1, 9\n        while k * cnt < n:\n            n -= k * cnt\n            k += 1\n            cnt *= 10\n        num = 10 ** (k - 1) + (n - 1) // k\n        idx = (n - 1) % k\n        return int(str(num)[idx])\n",
    java: "class Solution {\n    public int findNthDigit(int n) {\n        int k = 1, cnt = 9;\n        while ((long) k * cnt < n) {\n            n -= k * cnt;\n            ++k;\n            cnt *= 10;\n        }\n        int num = (int) Math.pow(10, k - 1) + (n - 1) / k;\n        int idx = (n - 1) % k;\n        return String.valueOf(num).charAt(idx) - '0';\n    }\n}",
