    python: "class Solution:\n    def characterReplacement(self, s: str, k: int) -> int:\n        cnt = Counter()\n        l = mx = 0\n        for r, c in enumerate(s):\n            cnt[c] += 1\n            mx = max(mx, cnt[c])\n            if r - l + 1 - mx > k:\n                cnt[s[l]] -= 1\n                l += 1\n        return len(s) - l\n",
    java: "class Solution {\n    public int characterReplacement(String s, int k) {\n        int[] cnt = new int[26];\n        int l = 0, mx = 0;\n        int n = s.length();\n        for (int r = 0; r < n; ++r) {\n            mx = Math.max(mx, ++cnt[s.charAt(r) - 'A']);\n            if (r - l + 1 - mx > k) {\n                --cnt[s.charAt(l++) - 'A'];\n            }\n        }\n        return n - l;\n    }\n}",
