    python: "\"\"\"\n# Definition for a Node.\nclass Node:\n    def __init__(self, val, prev, next, child):\n        self.val = val\n        self.prev = prev\n        self.next = next\n        self.child = child\n\"\"\"\n\n\nclass Solution:\n    def flatten(self, head: 'Node') -> 'Node':\n        def preorder(pre, cur):\n            if cur is None:\n                return pre\n            cur.prev = pre\n            pre.next = cur\n\n            t = cur.next\n            tail = preorder(cur, cur.child)\n            cur.child = None\n            return preorder(tail, t)\n\n        if head is None:\n            return None\n        dummy = Node(0, None, head, None)\n        preorder(dummy, head)\n        dummy.next.prev = None\n        return dummy.next\n",
