    java: "class Solution {\n    public List<Integer> findDisappearedNumbers(int[] nums) {\n        int n = nums.length;\n        boolean[] s = new boolean[n + 1];\n        for (int x : nums) {\n            s[x] = true;\n        }\n        List<Integer> ans = new ArrayList<>();\n        for (int i = 1; i <= n; i++) {\n            if (!s[i]) {\n                ans.add(i);\n            }\n        }\n        return ans;\n    }\n}",
