    python: "class Solution:\n    def findContentChildren(self, g: List[int], s: List[int]) -> int:\n        g.sort()\n        s.sort()\n        j = 0\n        for i, x in enumerate(g):\n            while j < len(s) and s[j] < g[i]:\n                j += 1\n            if j >= len(s):\n                return i\n            j += 1\n        return len(g)\n",
    java: "class Solution {\n    public int findContentChildren(int[] g, int[] s) {\n        Arrays.sort(g);\n        Arrays.sort(s);\n        int m = g.length;\n        int n = s.length;\n        for (int i = 0, j = 0; i < m; ++i) {\n            while (j < n && s[j] < g[i]) {\n                ++j;\n            }\n            if (j++ >= n) {\n                return i;\n            }\n        }\n        return m;\n    }\n}",
