    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def isConvex(self, points: List[List[int]]) -> bool:\n        n = len(points)\n        pre = cur = 0\n        for i in range(n):\n            x1 = points[(i + 1) % n][0] - points[i][0]\n            y1 = points[(i + 1) % n][1] - points[i][1]\n            x2 = points[(i + 2) % n][0] - points[i][0]\n            y2 = points[(i + 2) % n][1] - points[i][1]\n            cur = x1 * y2 - x2 * y1\n            if cur != 0:\n                if cur * pre < 0:\n                    return False\n                pre = cur\n        return True\n",
    java: "class Solution {\n    public boolean isConvex(List<List<Integer>> points) {\n        int n = points.size();\n        long pre = 0, cur = 0;\n        for (int i = 0; i < n; ++i) {\n            var p1 = points.get(i);\n            var p2 = points.get((i + 1) % n);\n            var p3 = points.get((i + 2) % n);\n            int x1 = p2.get(0) - p1.get(0);\n            int y1 = p2.get(1) - p1.get(1);\n            int x2 = p3.get(0) - p1.get(0);\n            int y2 = p3.get(1) - p1.get(1);\n            cur = x1 * y2 - x2 * y1;\n            if (cur != 0) {\n                if (cur * pre < 0) {\n                    return false;\n                }\n                pre = cur;\n            }\n        }\n        return true;\n    }\n}",
