    java: "class Solution {\n    public int findMaxLength(int[] nums) {\n        Map<Integer, Integer> d = new HashMap<>();\n        d.put(0, -1);\n        int ans = 0, s = 0;\n        for (int i = 0; i < nums.length; ++i) {\n            s += nums[i] == 1 ? 1 : -1;\n            if (d.containsKey(s)) {\n                ans = Math.max(ans, i - d.get(s));\n            } else {\n                d.put(s, i);\n            }\n        }\n        return ans;\n    }\n}",
