    python: "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def convertBST(self, root: TreeNode) -> TreeNode:\n        def dfs(root):\n            nonlocal s\n            if root is None:\n                return\n            dfs(root.right)\n            s += root.val\n            root.val = s\n            dfs(root.left)\n\n        s = 0\n        dfs(root)\n        return root\n",
    java: "/**\n * Definition for a binary tree node.\n * public class TreeNode {\n *     int val;\n *     TreeNode left;\n *     TreeNode right;\n *     TreeNode() {}\n *     TreeNode(int val) { this.val = val; }\n *     TreeNode(int val, TreeNode left, TreeNode right) {\n *         this.val = val;\n *         this.left = left;\n *         this.right = right;\n *     }\n * }\n */\nclass Solution {\n    private int s;\n\n    public TreeNode convertBST(TreeNode root) {\n        dfs(root);\n        return root;\n    }\n\n    private void dfs(TreeNode root) {\n        if (root == null) {\n            return;\n        }\n        dfs(root.right);\n        s += root.val;\n        root.val = s;\n        dfs(root.left);\n    }\n}",
