    python: "class Solution:\n    def findCircleNum(self, isConnected: List[List[int]]) -> int:\n        def dfs(i: int):\n            vis[i] = True\n            for j, x in enumerate(isConnected[i]):\n                if not vis[j] and x:\n                    dfs(j)\n\n        n = len(isConnected)\n        vis = [False] * n\n        ans = 0\n        for i in range(n):\n            if not vis[i]:\n                dfs(i)\n                ans += 1\n        return ans\n",
    java: "class Solution {\n    private int[][] g;\n    private boolean[] vis;\n\n    public int findCircleNum(int[][] isConnected) {\n        g = isConnected;\n        int n = g.length;\n        vis = new boolean[n];\n        int ans = 0;\n        for (int i = 0; i < n; ++i) {\n            if (!vis[i]) {\n                dfs(i);\n                ++ans;\n            }\n        }\n        return ans;\n    }\n\n    private void dfs(int i) {\n        vis[i] = true;\n        for (int j = 0; j < g.length; ++j) {\n            if (!vis[j] && g[i][j] == 1) {\n                dfs(j);\n            }\n        }\n    }\n}",
