    python: "class Solution:\n    def countSubstrings(self, s: str) -> int:\n        ans, n = 0, len(s)\n        for k in range(n * 2 - 1):\n            i, j = k // 2, (k + 1) // 2\n            while ~i and j < n and s[i] == s[j]:\n                ans += 1\n                i, j = i - 1, j + 1\n        return ans\n",
    java: "class Solution {\n    public int countSubstrings(String s) {\n        int ans = 0;\n        int n = s.length();\n        for (int k = 0; k < n * 2 - 1; ++k) {\n            int i = k / 2, j = (k + 1) / 2;\n            while (i >= 0 && j < n && s.charAt(i) == s.charAt(j)) {\n                ++ans;\n                --i;\n                ++j;\n            }\n        }\n        return ans;\n    }\n}",
