    java: "class Solution {\n    public List<Integer> findClosestElements(int[] arr, int k, int x) {\n        List<Integer> ans = Arrays.stream(arr)\n                                .boxed()\n                                .sorted((a, b) -> {\n                                    int v = Math.abs(a - x) - Math.abs(b - x);\n                                    return v == 0 ? a - b : v;\n                                })\n                                .collect(Collectors.toList());\n        ans = ans.subList(0, k);\n        Collections.sort(ans);\n        return ans;\n    }\n}",
