    python: "class Solution:\n    def findRedundantConnection(self, edges: List[List[int]]) -> List[int]:\n        def find(x: int) -> int:\n            if p[x] != x:\n                p[x] = find(p[x])\n            return p[x]\n\n        p = list(range(len(edges)))\n        for a, b in edges:\n            pa, pb = find(a - 1), find(b - 1)\n            if pa == pb:\n                return [a, b]\n            p[pa] = pb\n",
    java: "class Solution {\n    private int[] p;\n\n    public int[] findRedundantConnection(int[][] edges) {\n        int n = edges.length;\n        p = new int[n];\n        for (int i = 0; i < n; ++i) {\n            p[i] = i;\n        }\n        for (int i = 0;; ++i) {\n            int pa = find(edges[i][0] - 1);\n            int pb = find(edges[i][1] - 1);\n            if (pa == pb) {\n                return edges[i];\n            }\n            p[pa] = pb;\n        }\n    }\n\n    private int find(int x) {\n        if (p[x] != x) {\n            p[x] = find(p[x]);\n        }\n        return p[x];\n    }\n}\n",
