    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def maxAreaOfIsland(self, grid: List[List[int]]) -> int:\n        def dfs(i: int, j: int) -> int:\n            if grid[i][j] == 0:\n                return 0\n            ans = 1\n            grid[i][j] = 0\n            dirs = (-1, 0, 1, 0, -1)\n            for a, b in pairwise(dirs):\n                x, y = i + a, j + b\n                if 0 <= x < m and 0 <= y < n:\n                    ans += dfs(x, y)\n            return ans\n\n        m, n = len(grid), len(grid[0])\n        return max(dfs(i, j) for i in range(m) for j in range(n))\n",
    java: "class Solution {\n    private int m;\n    private int n;\n    private int[][] grid;\n\n    public int maxAreaOfIsland(int[][] grid) {\n        m = grid.length;\n        n = grid[0].length;\n        this.grid = grid;\n        int ans = 0;\n        for (int i = 0; i < m; ++i) {\n            for (int j = 0; j < n; ++j) {\n                ans = Math.max(ans, dfs(i, j));\n            }\n        }\n        return ans;\n    }\n\n    private int dfs(int i, int j) {\n        if (grid[i][j] == 0) {\n            return 0;\n        }\n        int ans = 1;\n        grid[i][j] = 0;\n        int[] dirs = {-1, 0, 1, 0, -1};\n        for (int k = 0; k < 4; ++k) {\n            int x = i + dirs[k], y = j + dirs[k + 1];\n            if (x >= 0 && x < m && y >= 0 && y < n) {\n                ans += dfs(x, y);\n            }\n        }\n        return ans;\n    }\n}",
