    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def swimInWater(self, grid: List[List[int]]) -> int:\n        def find(x: int) -> int:\n            if p[x] != x:\n                p[x] = find(p[x])\n            return p[x]\n\n        n = len(grid)\n        m = n * n\n        p = list(range(m))\n        hi = [0] * m\n        for i, row in enumerate(grid):\n            for j, h in enumerate(row):\n                hi[h] = i * n + j\n        dirs = (-1, 0, 1, 0, -1)\n        for t in range(m):\n            x, y = divmod(hi[t], n)\n            for dx, dy in pairwise(dirs):\n                nx, ny = x + dx, y + dy\n                if 0 <= nx < n and 0 <= ny < n and grid[nx][ny] <= t:\n                    p[find(x * n + y)] = find(nx * n + ny)\n            if find(0) == find(m - 1):\n                return t\n        return 0\n",
    java: "class Solution {\n    public int swimInWater(int[][] grid) {\n        int n = grid.length;\n        int m = n * n;\n        int[] p = new int[m];\n        Arrays.setAll(p, i -> i);\n        IntUnaryOperator find = new IntUnaryOperator() {\n            @Override\n            public int applyAsInt(int x) {\n                if (p[x] != x) p[x] = applyAsInt(p[x]);\n                return p[x];\n            }\n        };\n\n        int[] hi = new int[m];\n        for (int i = 0; i < n; i++) {\n            for (int j = 0; j < n; j++) {\n                hi[grid[i][j]] = i * n + j;\n            }\n        }\n\n        int[] dirs = {-1, 0, 1, 0, -1};\n\n        for (int t = 0; t < m; t++) {\n            int id = hi[t];\n            int x = id / n, y = id % n;\n            for (int k = 0; k < 4; k++) {\n                int nx = x + dirs[k], ny = y + dirs[k + 1];\n                if (nx >= 0 && nx < n && ny >= 0 && ny < n && grid[nx][ny] <= t) {\n                    int a = find.applyAsInt(x * n + y);\n                    int b = find.applyAsInt(nx * n + ny);\n                    p[a] = b;\n                }\n            }\n            if (find.applyAsInt(0) == find.applyAsInt(m - 1)) {\n                return t;\n            }\n        }\n        return 0;\n    }\n}\n",
