    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def largestTriangleArea(self, points: List[List[int]]) -> float:\n        ans = 0\n        for x1, y1 in points:\n            for x2, y2 in points:\n                for x3, y3 in points:\n                    u1, v1 = x2 - x1, y2 - y1\n                    u2, v2 = x3 - x1, y3 - y1\n                    t = abs(u1 * v2 - u2 * v1) / 2\n                    ans = max(ans, t)\n        return ans\n",
    java: "class Solution {\n    public double largestTriangleArea(int[][] points) {\n        double ans = 0;\n        for (int[] p1 : points) {\n            int x1 = p1[0], y1 = p1[1];\n            for (int[] p2 : points) {\n                int x2 = p2[0], y2 = p2[1];\n                for (int[] p3 : points) {\n                    int x3 = p3[0], y3 = p3[1];\n                    int u1 = x2 - x1, v1 = y2 - y1;\n                    int u2 = x3 - x1, v2 = y3 - y1;\n                    double t = Math.abs(u1 * v2 - u2 * v1) / 2.0;\n                    ans = Math.max(ans, t);\n                }\n            }\n        }\n        return ans;\n    }\n}",
