    java: "class Solution {\n    public int matrixScore(int[][] grid) {\n        int m = grid.length, n = grid[0].length;\n        for (int i = 0; i < m; ++i) {\n            if (grid[i][0] == 0) {\n                for (int j = 0; j < n; ++j) {\n                    grid[i][j] ^= 1;\n                }\n            }\n        }\n        int ans = 0;\n        for (int j = 0; j < n; ++j) {\n            int cnt = 0;\n            for (int i = 0; i < m; ++i) {\n                cnt += grid[i][j];\n            }\n            ans += Math.max(cnt, m - cnt) * (1 << (n - j - 1));\n        }\n        return ans;\n    }\n}",
