    python: "class Solution:\n    def advantageCount(self, nums1: List[int], nums2: List[int]) -> List[int]:\n        nums1.sort()\n        t = sorted((v, i) for i, v in enumerate(nums2))\n        n = len(nums2)\n        ans = [0] * n\n        i, j = 0, n - 1\n        for v in nums1:\n            if v <= t[i][0]:\n                ans[t[j][1]] = v\n                j -= 1\n            else:\n                ans[t[i][1]] = v\n                i += 1\n        return ans\n",
    java: "class Solution {\n    public int[] advantageCount(int[] nums1, int[] nums2) {\n        int n = nums1.length;\n        int[][] t = new int[n][2];\n        for (int i = 0; i < n; ++i) {\n            t[i] = new int[] {nums2[i], i};\n        }\n        Arrays.sort(t, (a, b) -> a[0] - b[0]);\n        Arrays.sort(nums1);\n        int[] ans = new int[n];\n        int i = 0, j = n - 1;\n        for (int v : nums1) {\n            if (v <= t[i][0]) {\n                ans[t[j--][1]] = v;\n            } else {\n                ans[t[i++][1]] = v;\n            }\n        }\n        return ans;\n    }\n}",
