    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def threeSumMulti(self, arr: List[int], target: int) -> int:\n        mod = 10**9 + 7\n        cnt = Counter(arr)\n        ans = 0\n        for j, b in enumerate(arr):\n            cnt[b] -= 1\n            for a in arr[:j]:\n                c = target - a - b\n                ans = (ans + cnt[c]) % mod\n        return ans\n",
    java: "class Solution {\n    public int threeSumMulti(int[] arr, int target) {\n        final int mod = (int) 1e9 + 7;\n        int[] cnt = new int[101];\n        for (int x : arr) {\n            ++cnt[x];\n        }\n        int n = arr.length;\n        int ans = 0;\n        for (int j = 0; j < n; ++j) {\n            --cnt[arr[j]];\n            for (int i = 0; i < j; ++i) {\n                int c = target - arr[i] - arr[j];\n                if (c >= 0 && c < cnt.length) {\n                    ans = (ans + cnt[c]) % mod;\n                }\n            }\n        }\n        return ans;\n    }\n}",
