    python: "class Solution:\n    def subarraysDivByK(self, nums: List[int], k: int) -> int:\n        cnt = Counter({0: 1})\n        ans = s = 0\n        for x in nums:\n            s = (s + x) % k\n            ans += cnt[s]\n            cnt[s] += 1\n        return ans\n",
    java: "class Solution {\n    public int subarraysDivByK(int[] nums, int k) {\n        Map<Integer, Integer> cnt = new HashMap<>();\n        cnt.put(0, 1);\n        int ans = 0, s = 0;\n        for (int x : nums) {\n            s = ((s + x) % k + k) % k;\n            ans += cnt.getOrDefault(s, 0);\n            cnt.merge(s, 1, Integer::sum);\n        }\n        return ans;\n    }\n}",
