    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def sortedSquares(self, nums: List[int]) -> List[int]:\n        ans = []\n        i, j = 0, len(nums) - 1\n        while i <= j:\n            a = nums[i] * nums[i]\n            b = nums[j] * nums[j]\n            if a > b:\n                ans.append(a)\n                i += 1\n            else:\n                ans.append(b)\n                j -= 1\n        return ans[::-1]\n",
    java: "class Solution {\n    public int[] sortedSquares(int[] nums) {\n        int n = nums.length;\n        int[] ans = new int[n];\n        for (int i = 0, j = n - 1, k = n - 1; i <= j; --k) {\n            int a = nums[i] * nums[i];\n            int b = nums[j] * nums[j];\n            if (a > b) {\n                ans[k] = a;\n                ++i;\n            } else {\n                ans[k] = b;\n                --j;\n            }\n        }\n        return ans;\n    }\n}",
