    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def strWithout3a3b(self, a: int, b: int) -> str:\n        ans = []\n        while a and b:\n            if a > b:\n                ans.append('aab')\n                a, b = a - 2, b - 1\n            elif a < b:\n                ans.append('bba')\n                a, b = a - 1, b - 2\n            else:\n                ans.append('ab')\n                a, b = a - 1, b - 1\n        if a:\n            ans.append('a' * a)\n        if b:\n            ans.append('b' * b)\n        return ''.join(ans)\n",
    java: "class Solution {\n    public String strWithout3a3b(int a, int b) {\n        StringBuilder ans = new StringBuilder();\n        while (a > 0 && b > 0) {\n            if (a > b) {\n                ans.append(\"aab\");\n                a -= 2;\n                b -= 1;\n            } else if (a < b) {\n                ans.append(\"bba\");\n                a -= 1;\n                b -= 2;\n            } else {\n                ans.append(\"ab\");\n                --a;\n                --b;\n            }\n        }\n        if (a > 0) {\n            ans.append(\"a\".repeat(a));\n        }\n        if (b > 0) {\n            ans.append(\"b\".repeat(b));\n        }\n        return ans.toString();\n    }\n}",
