    java: "class Solution {\n    public int[] corpFlightBookings(int[][] bookings, int n) {\n        int[] ans = new int[n];\n        for (var e : bookings) {\n            int first = e[0], last = e[1], seats = e[2];\n            ans[first - 1] += seats;\n            if (last < n) {\n                ans[last] -= seats;\n            }\n        }\n        for (int i = 1; i < n; ++i) {\n            ans[i] += ans[i - 1];\n        }\n        return ans;\n    }\n}",
