    python: "class Solution:\n    def isValidPalindrome(self, s: str, k: int) -> bool:\n        n = len(s)\n        f = [[0] * n for _ in range(n)]\n        for i in range(n):\n            f[i][i] = 1\n        for i in range(n - 2, -1, -1):\n            for j in range(i + 1, n):\n                if s[i] == s[j]:\n                    f[i][j] = f[i + 1][j - 1] + 2\n                else:\n                    f[i][j] = max(f[i + 1][j], f[i][j - 1])\n                if f[i][j] + k >= n:\n                    return True\n        return False\n",
    java: "class Solution {\n    public boolean isValidPalindrome(String s, int k) {\n        int n = s.length();\n        int[][] f = new int[n][n];\n        for (int i = 0; i < n; ++i) {\n            f[i][i] = 1;\n        }\n        for (int i = n - 2; i >= 0; --i) {\n            for (int j = i + 1; j < n; ++j) {\n                if (s.charAt(i) == s.charAt(j)) {\n                    f[i][j] = f[i + 1][j - 1] + 2;\n                } else {\n                    f[i][j] = Math.max(f[i + 1][j], f[i][j - 1]);\n                }\n                if (f[i][j] + k >= n) {\n                    return true;\n                }\n            }\n        }\n        return false;\n    }\n}",
