    name: "Optimal Approach",
    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "class Solution:\n    def maximizeSweetness(self, sweetness: List[int], k: int) -> int:\n        def check(x: int) -> bool:\n            s = cnt = 0\n            for v in sweetness:\n                s += v\n                if s >= x:\n                    s = 0\n                    cnt += 1\n            return cnt > k\n\n        l, r = 0, sum(sweetness)\n        while l < r:\n            mid = (l + r + 1) >> 1\n            if check(mid):\n                l = mid\n            else:\n                r = mid - 1\n        return l\n",
    java: "class Solution {\n    public int maximizeSweetness(int[] sweetness, int k) {\n        int l = 0, r = 0;\n        for (int v : sweetness) {\n            r += v;\n        }\n        while (l < r) {\n            int mid = (l + r + 1) >> 1;\n            if (check(sweetness, mid, k)) {\n                l = mid;\n            } else {\n                r = mid - 1;\n            }\n        }\n        return l;\n    }\n\n    private boolean check(int[] nums, int x, int k) {\n        int s = 0, cnt = 0;\n        for (int v : nums) {\n            s += v;\n            if (s >= x) {\n                s = 0;\n                ++cnt;\n            }\n        }\n        return cnt > k;\n    }\n}",
