    python: "class Solution:\n    def minSetSize(self, arr: List[int]) -> int:\n        cnt = Counter(arr)\n        ans = m = 0\n        for _, v in cnt.most_common():\n            m += v\n            ans += 1\n            if m * 2 >= len(arr):\n                break\n        return ans\n",
    java: "class Solution {\n    public int minSetSize(int[] arr) {\n        int mx = 0;\n        for (int x : arr) {\n            mx = Math.max(mx, x);\n        }\n        int[] cnt = new int[mx + 1];\n        for (int x : arr) {\n            ++cnt[x];\n        }\n        Arrays.sort(cnt);\n        int ans = 0;\n        int m = 0;\n        for (int i = mx;; --i) {\n            if (cnt[i] > 0) {\n                m += cnt[i];\n                ++ans;\n                if (m * 2 >= arr.length) {\n                    return ans;\n                }\n            }\n        }\n    }\n}",
