    python: "@cache\ndef f(x: int) -> int:\n    ans = 0\n    while x != 1:\n        if x % 2 == 0:\n            x //= 2\n        else:\n            x = 3 * x + 1\n        ans += 1\n    return ans\n\n\nclass Solution:\n    def getKth(self, lo: int, hi: int, k: int) -> int:\n        return sorted(range(lo, hi + 1), key=f)[k - 1]\n",
    java: "class Solution {\n    public int getKth(int lo, int hi, int k) {\n        Integer[] nums = new Integer[hi - lo + 1];\n        for (int i = lo; i <= hi; ++i) {\n            nums[i - lo] = i;\n        }\n        Arrays.sort(nums, (a, b) -> {\n            int fa = f(a), fb = f(b);\n            return fa == fb ? a - b : fa - fb;\n        });\n        return nums[k - 1];\n    }\n\n    private int f(int x) {\n        int ans = 0;\n        for (; x != 1; ++ans) {\n            if (x % 2 == 0) {\n                x /= 2;\n            } else {\n                x = x * 3 + 1;\n            }\n        }\n        return ans;\n    }\n}",
