    complexity: {"time": "O(N)", "space": "O(1)"},
    python: "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def goodNodes(self, root: TreeNode) -> int:\n        def dfs(root: TreeNode, mx: int):\n            if root is None:\n                return\n            nonlocal ans\n            if mx <= root.val:\n                ans += 1\n                mx = root.val\n            dfs(root.left, mx)\n            dfs(root.right, mx)\n\n        ans = 0\n        dfs(root, -1000000)\n        return ans\n",
    java: "/**\n * Definition for a binary tree node.\n * public class TreeNode {\n *     int val;\n *     TreeNode left;\n *     TreeNode right;\n *     TreeNode() {}\n *     TreeNode(int val) { this.val = val; }\n *     TreeNode(int val, TreeNode left, TreeNode right) {\n *         this.val = val;\n *         this.left = left;\n *         this.right = right;\n *     }\n * }\n */\nclass Solution {\n    private int ans = 0;\n\n    public int goodNodes(TreeNode root) {\n        dfs(root, -100000);\n        return ans;\n    }\n\n    private void dfs(TreeNode root, int mx) {\n        if (root == null) {\n            return;\n        }\n        if (mx <= root.val) {\n            ++ans;\n            mx = root.val;\n        }\n        dfs(root.left, mx);\n        dfs(root.right, mx);\n    }\n}",
