    python: "class Solution:\n    def minStoneSum(self, piles: List[int], k: int) -> int:\n        pq = [-x for x in piles]\n        heapify(pq)\n        for _ in range(k):\n            heapreplace(pq, pq[0] // 2)\n        return -sum(pq)\n",
    java: "class Solution {\n    public int minStoneSum(int[] piles, int k) {\n        PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);\n        for (int x : piles) {\n            pq.offer(x);\n        }\n        while (k-- > 0) {\n            int x = pq.poll();\n            pq.offer(x - x / 2);\n        }\n        int ans = 0;\n        while (!pq.isEmpty()) {\n            ans += pq.poll();\n        }\n        return ans;\n    }\n}",
