    python: "class Solution:\n    def validPath(\n        self, n: int, edges: List[List[int]], source: int, destination: int\n    ) -> bool:\n        def dfs(i: int) -> bool:\n            if i == destination:\n                return True\n            if i in vis:\n                return False\n            return any(dfs(j) for j in g[i])\n\n        g = [[] for _ in range(n)]\n        for u, v in edges:\n            g[u].append(v)\n            g[v].append(u)\n        vis = set()\n        return dfs(source)\n",
    java: "class Solution {\n    private int destination;\n    private boolean[] vis;\n    private List<Integer>[] g;\n\n    public boolean validPath(int n, int[][] edges, int source, int destination) {\n        this.destination = destination;\n        vis = new boolean[n];\n        g = new List[n];\n        Arrays.setAll(g, i -> new ArrayList<>());\n        for (var e : edges) {\n            int u = e[0], v = e[1];\n            g[u].add(v);\n            g[v].add(u);\n        }\n        return dfs(source);\n    }\n\n    private boolean dfs(int i) {\n        if (i == destination) {\n            return true;\n        }\n        vis[i] = true;\n        for (var j : g[i]) {\n            if (!vis[j] && dfs(j)) {\n                return true;\n            }\n        }\n        return false;\n    }\n}\n",
