    python: "class Solution:\n    def halveArray(self, nums: List[int]) -> int:\n        s = sum(nums) / 2\n        pq = []\n        for x in nums:\n            heappush(pq, -x)\n        ans = 0\n        while s > 0:\n            t = -heappop(pq) / 2\n            s -= t\n            heappush(pq, -t)\n            ans += 1\n        return ans\n",
    java: "class Solution {\n    public int halveArray(int[] nums) {\n        PriorityQueue<Double> pq = new PriorityQueue<>(Collections.reverseOrder());\n        double s = 0;\n        for (int x : nums) {\n            s += x;\n            pq.offer((double) x);\n        }\n        s /= 2.0;\n        int ans = 0;\n        while (s > 0) {\n            double t = pq.poll() / 2.0;\n            s -= t;\n            pq.offer(t);\n            ++ans;\n        }\n        return ans;\n    }\n}\n",
