    python: "class Solution:\n    def closestMeetingNode(self, edges: List[int], node1: int, node2: int) -> int:\n        def f(i):\n            dist = [inf] * n\n            dist[i] = 0\n            q = deque([i])\n            while q:\n                i = q.popleft()\n                for j in g[i]:\n                    if dist[j] == inf:\n                        dist[j] = dist[i] + 1\n                        q.append(j)\n            return dist\n\n        g = defaultdict(list)\n        for i, j in enumerate(edges):\n            if j != -1:\n                g[i].append(j)\n        n = len(edges)\n        d1 = f(node1)\n        d2 = f(node2)\n        ans, d = -1, inf\n        for i, (a, b) in enumerate(zip(d1, d2)):\n            if (t := max(a, b)) < d:\n                d = t\n                ans = i\n        return ans\n",
    java: "class Solution {\n    private int n;\n    private List<Integer>[] g;\n\n    public int closestMeetingNode(int[] edges, int node1, int node2) {\n        n = edges.length;\n        g = new List[n];\n        Arrays.setAll(g, k -> new ArrayList<>());\n        for (int i = 0; i < n; ++i) {\n            if (edges[i] != -1) {\n                g[i].add(edges[i]);\n            }\n        }\n        int[] d1 = f(node1);\n        int[] d2 = f(node2);\n        int d = 1 << 30;\n        int ans = -1;\n        for (int i = 0; i < n; ++i) {\n            int t = Math.max(d1[i], d2[i]);\n            if (t < d) {\n                d = t;\n                ans = i;\n            }\n        }\n        return ans;\n    }\n\n    private int[] f(int i) {\n        int[] dist = new int[n];\n        Arrays.fill(dist, 1 << 30);\n        dist[i] = 0;\n        Deque<Integer> q = new ArrayDeque<>();\n        q.offer(i);\n        while (!q.isEmpty()) {\n            i = q.poll();\n            for (int j : g[i]) {\n                if (dist[j] == 1 << 30) {\n                    dist[j] = dist[i] + 1;\n                    q.offer(j);\n                }\n            }\n        }\n        return dist;\n    }\n}",
