    python: "class Solution:\n    def minimizeArrayValue(self, nums: List[int]) -> int:\n        def check(mx):\n            d = 0\n            for x in nums[:0:-1]:\n                d = max(0, d + x - mx)\n            return nums[0] + d <= mx\n\n        left, right = 0, max(nums)\n        while left < right:\n            mid = (left + right) >> 1\n            if check(mid):\n                right = mid\n            else:\n                left = mid + 1\n        return left\n",
    java: "class Solution {\n    private int[] nums;\n\n    public int minimizeArrayValue(int[] nums) {\n        this.nums = nums;\n        int left = 0, right = max(nums);\n        while (left < right) {\n            int mid = (left + right) >> 1;\n            if (check(mid)) {\n                right = mid;\n            } else {\n                left = mid + 1;\n            }\n        }\n        return left;\n    }\n\n    private boolean check(int mx) {\n        long d = 0;\n        for (int i = nums.length - 1; i > 0; --i) {\n            d = Math.max(0, d + nums[i] - mx);\n        }\n        return nums[0] + d <= mx;\n    }\n\n    private int max(int[] nums) {\n        int v = nums[0];\n        for (int x : nums) {\n            v = Math.max(v, x);\n        }\n        return v;\n    }\n}",
