    java: "class Solution {\n    public int maxFrequencyElements(int[] nums) {\n        int[] cnt = new int[101];\n        for (int x : nums) {\n            ++cnt[x];\n        }\n        int ans = 0, mx = -1;\n        for (int x : cnt) {\n            if (mx < x) {\n                mx = x;\n                ans = x;\n            } else if (mx == x) {\n                ans += x;\n            }\n        }\n        return ans;\n    }\n}",
